import{_ as a,c as e,o as m,b as t}from"./app.5ff54e83.js";const h=JSON.parse('{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 3-4","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 3-4","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-02-09T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/3-4/index.md"}'),p={name:"texts/shiva-sutra-vimarshini/3/3-4/index.md"},i=t('<div class="stanza"><a href="#s3.3" id="s3.3" class="num">3.3</a><div class="sans"><p>\u0928\u0928\u0941 \u091A</p><blockquote><p>\u091C\u094D\u091E\u093E\u0928\u0902 \u092A\u094D\u0930\u0915\u093E\u0936\u0915\u0902 \u0932\u094B\u0915 \u0906\u0924\u094D\u092E\u093E \u091A\u0948\u0935 \u092A\u094D\u0930\u0915\u093E\u0936\u0915\u0903\u0964<br> \u0905\u0928\u092F\u094B\u0930\u092A\u0943\u0925\u0917\u094D\u092D\u093E\u0935\u093E\u091C\u094D\u091C\u094D\u091E\u093E\u0928\u0947 \u091C\u094D\u091E\u093E\u0928\u0940 \u092A\u094D\u0930\u0915\u093E\u0936\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u094B\u0915\u094D\u0924\u0926\u0943\u0937\u094D\u091F\u094D\u092F\u093E \u091C\u094D\u091E\u093E\u0928\u092E\u092A\u093F \u092A\u094D\u0930\u0915\u093E\u0936\u092E\u092F\u092E\u0947\u0935\u0947\u0924\u093F \u0915\u0925\u092E\u0938\u094D\u092F \u092C\u0928\u094D\u0927\u0930\u0942\u092A\u0924\u094D\u0935\u092E\u094D\u0964 \u0938\u0924\u094D\u092F\u092E\u0947\u0924\u0926\u094D\u092F\u0926\u093F \u092A\u0930\u092E\u0947\u0936\u094D\u0935\u0930\u092A\u094D\u0930\u0938\u093E\u0926\u093E\u0926\u0947\u0935\u0902 \u092A\u094D\u0930\u0924\u094D\u092F\u092D\u093F\u091C\u094D\u091E\u093E\u092F\u0947\u0924 \u092F\u0926\u093E \u0924\u0941 \u0924\u0928\u094D\u092E\u093E\u092F\u093E\u0936\u0915\u094D\u0924\u093F\u0924\u094B \u0928\u0948\u0935\u0902 \u0935\u093F\u092E\u0930\u094D\u0936\u0938\u094D\u0924\u0926\u093E\u2014</p><blockquote><p><strong>\u0915\u0932\u093E\u0926\u0940\u0928\u093E\u0902 \u0924\u0924\u094D\u0924\u094D\u0935\u093E\u0928\u093E\u092E\u0935\u093F\u0935\u0947\u0915\u094B \u092E\u093E\u092F\u093E\u0965\u0969\u0965</strong></p></blockquote><p>\u0915\u093F\u091E\u094D\u091A\u093F\u0924\u094D\u0915\u0930\u094D\u0924\u0943\u0924\u093E\u0926\u093F\u0930\u0942\u092A\u0915\u0932\u093E\u0926\u093F\u0915\u094D\u0937\u093F\u0924\u094D\u092F\u0928\u094D\u0924\u093E\u0928\u093E\u0902 \u0924\u0924\u094D\u0924\u094D\u0935\u093E\u0928\u093E\u0902 \u0915\u091E\u094D\u091A\u0941\u0915\u092A\u0941\u0930\u094D\u092F\u0937\u094D\u091F\u0915\u0938\u094D\u0925\u0942\u0932\u0926\u0947\u0939\u0924\u094D\u0935\u0947\u0928\u093E\u0935\u0938\u094D\u0925\u093F\u0924\u093E\u0928\u093E\u0902 \u092F\u094B\u093D\u092F\u092E\u0935\u093F\u0935\u0947\u0915\u0903 \u092A\u0943\u0925\u0915\u094D\u0924\u094D\u0935\u093E\u092D\u093F\u092E\u0924\u093E\u0928\u093E\u092E\u0947\u0935\u093E\u092A\u0943\u0925\u0917\u093E\u0924\u094D\u092E\u0924\u094D\u0935\u0947\u0928 \u092A\u094D\u0930\u0924\u093F\u092A\u0924\u094D\u0924\u093F\u0903 \u0938\u093E \u092E\u093E\u092F\u093E \u0924\u0924\u094D\u0924\u094D\u0935\u093E\u0916\u094D\u092F\u093E\u0924\u093F\u092E\u092F\u0903 \u092A\u094D\u0930\u092A\u091E\u094D\u091A\u0903\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0924\u0928\u094D\u0924\u094D\u0930\u0938\u0926\u094D\u092D\u093E\u0935\u0947</p><blockquote><p>\u0915\u0932\u094B\u0926\u094D\u0935\u0932\u093F\u0924\u091A\u0948\u0924\u0928\u094D\u092F\u094B \u0935\u093F\u0926\u094D\u092F\u093E\u0926\u0930\u094D\u0936\u093F\u0924\u0917\u094B\u091A\u0930\u0903\u0964<br> \u0930\u093E\u0917\u0947\u0923 \u0930\u091E\u094D\u091C\u093F\u0924\u093E\u0924\u094D\u092E\u093E\u0938\u094C \u092C\u0941\u0926\u094D\u0927\u094D\u092F\u093E\u0926\u093F\u0915\u0930\u0923\u0948\u0930\u094D\u092F\u0941\u0924\u0903\u0965<br> \u090F\u0935\u0902 \u092E\u093E\u092F\u093E\u0924\u094D\u092E\u0915\u094B \u092C\u0928\u094D\u0927\u0903 \u092A\u094D\u0930\u094B\u0915\u094D\u0924\u0938\u094D\u0924\u0938\u094D\u092F \u0926\u0930\u093E\u0924\u094D\u092E\u0915\u0903\u0964<br> \u0924\u0926\u093E\u0936\u094D\u0930\u092F\u0917\u0941\u0923\u094B \u0927\u0930\u094D\u092E\u094B\u093D\u0927\u0930\u094D\u092E\u0936\u094D\u091A\u0948\u0935 \u0938\u092E\u093E\u0938\u0924\u0903\u0965<br> \u0924\u0924\u094D\u0930\u093E\u0938\u094C \u0938\u0902\u0938\u094D\u0925\u093F\u0924\u0903 \u092A\u093E\u0936\u094D\u092F\u0903 \u092A\u093E\u0936\u093F\u0924\u0938\u094D\u0924\u0948\u0938\u094D\u0924\u0941 \u0924\u093F\u0937\u094D\u0920\u0924\u093F\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0938\u094D\u092A\u0928\u094D\u0926\u0947 \u0924\u0941</p><blockquote><p>\u0905\u092A\u094D\u0930\u092C\u0941\u0926\u094D\u0927\u0927\u093F\u092F\u0938\u094D\u0924\u094D\u0935\u0947\u0924\u0947 \u0938\u094D\u0935\u0938\u094D\u0925\u093F\u0924\u093F\u0938\u094D\u0925\u0917\u0928\u094B\u0926\u094D\u092F\u0924\u093E\u0903\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928\u0948\u0924\u0926\u094D\u092D\u0919\u094D\u0917\u094D\u092F\u094B\u0915\u094D\u0924\u092E\u094D\u0965\u0969\u0965</p></div><div class="trans"><p>Nanu ca</p><blockquote><p>J\xF1\u0101na\u1E41 prak\u0101\u015Baka\u1E41 loka \u0101tm\u0101 caiva prak\u0101\u015Baka\u1E25|<br> Anayorap\u1E5Bthagbh\u0101v\u0101jj\xF1\u0101ne j\xF1\u0101n\u012B prak\u0101\u015Bate||</p></blockquote><p>iti \u015Br\u012Bvij\xF1\u0101nabhairavoktad\u1E5B\u1E63\u1E6Dy\u0101 j\xF1\u0101namapi prak\u0101\u015Bamayameveti kathamasya bandhar\u016Bpatvam| Satyametadyadi parame\u015Bvarapras\u0101d\u0101deva\u1E41 pratyabhij\xF1\u0101yeta yad\u0101 tu tanm\u0101y\u0101\u015Baktito naiva\u1E41 vimar\u015Bastad\u0101\u2014</p><blockquote><p><strong>Kal\u0101d\u012Bn\u0101\u1E41 tattv\u0101n\u0101maviveko m\u0101y\u0101||3||</strong></p></blockquote><p>Ki\xF1citkart\u1E5Bt\u0101dir\u016Bpakal\u0101dik\u1E63ityant\u0101n\u0101\u1E41 tattv\u0101n\u0101\u1E41 ka\xF1cukapurya\u1E63\u1E6Dakasth\u016Bladehatven\u0101vasthit\u0101n\u0101\u1E41 yo&#39;yamaviveka\u1E25 p\u1E5Bthaktv\u0101bhimat\u0101n\u0101mev\u0101p\u1E5Bthag\u0101tmatvena pratipatti\u1E25 s\u0101 m\u0101y\u0101 tattv\u0101khy\u0101timaya\u1E25 prapa\xF1ca\u1E25| Tadukta\u1E41 \u015Br\u012Btantrasadbh\u0101ve</p><blockquote><p>Kalodvalitacaitanyo vidy\u0101dar\u015Bitagocara\u1E25|<br> R\u0101ge\u1E47a ra\xF1jit\u0101tm\u0101sau buddhy\u0101dikara\u1E47airyuta\u1E25||<br> Eva\u1E41 m\u0101y\u0101tmako bandha\u1E25 proktastasya dar\u0101tmaka\u1E25|<br> Tad\u0101\u015Brayagu\u1E47o dharmo&#39;dharma\u015Bcaiva sam\u0101sata\u1E25||<br> Tatr\u0101sau sa\u1E41sthita\u1E25 p\u0101\u015Bya\u1E25 p\u0101\u015Bitastaistu ti\u1E63\u1E6Dhati|</p></blockquote><p>iti| Spande tu</p><blockquote><p>Aprabuddhadhiyastvete svasthitisthaganodyat\u0101\u1E25|</p></blockquote><p>ityanenaitadbha\u1E45gyoktam||3||</p></div><p>\u0412\u043E\u0437\u0440\u0430\u0436\u0435\u043D\u0438\u0435 <em>(nanu ca)</em>! \u0412\u0432\u0438\u0434\u0443 \u0442\u043E\u0433\u043E <em>(d\u1E5B\u1E63\u1E6Dy\u0101)</em>, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(ukta)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Vij\xF1\u0101nabhairava <em>(\u015Br\u012B-vij\xF1\u0101nabhairava)</em>:</p><blockquote><p>&quot;\u0412 \u043C\u0438\u0440\u0435 <em>(loke)</em>, \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> [\u2014 \u044D\u0442\u043E \u0442\u043E], \u0447\u0442\u043E \u0434\u0430\u0435\u0442 \u0441\u0432\u0435\u0442 <em>(prak\u0101\u015Bakam)</em> \u0438 <em>(ca eva)</em> \u0101tm\u0101 <em>(\u0101tm\u0101)</em> [\u2014 \u044D\u0442\u043E \u0442\u043E], \u0447\u0442\u043E \u0434\u0430\u0435\u0442 \u0441\u0432\u0435\u0442 <em>(prak\u0101\u015Baka\u1E25)</em>. \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439 <em>(j\xF1\u0101n\u012B)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F, \u0438\u043B\u0438 \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(prak\u0101\u015Bate)</em> \u0432 \u0437\u043D\u0430\u043D\u0438\u0438 <em>(j\xF1\u0101ne)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043D\u0435\u0442 <em>(a... bh\u0101v\u0101t)</em> \u0440\u0430\u0437\u043D\u0438\u0446\u044B <em>(p\u1E5Bthak)</em> \u043C\u0435\u0436\u0434\u0443 \u044D\u0442\u0438\u043C\u0438 \u0434\u0432\u0443\u043C\u044F <em>(anayo\u1E25... iti)</em> --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, \u043C\u0435\u0436\u0434\u0443 \u0437\u043D\u0430\u043D\u0438\u0435\u043C \u0438 \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u043C--<sup>1</sup>&quot;||</p></blockquote><p>[\u043F\u043E\u044D\u0442\u043E\u043C\u0443,] \u0434\u0430\u0436\u0435 <em>(api)</em> &quot; [\u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0435 \u0443\u043C\u043E\u043C] \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043E <em>(mayam eva)</em> \u0441\u0432\u0435\u0442\u043E\u043C <em>(prak\u0101\u015Ba... iti)</em>&quot;, [\u0442\u043E\u0433\u0434\u0430,] \u043A\u0430\u043A <em>(katham)</em> \u043E\u043D\u043E [\u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C] --\u0442.\u0435. \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0435 \u0443\u043C\u043E\u043C \u0437\u043D\u0430\u043D\u0438\u0435--\u0440\u0430\u0431\u0441\u0442\u0432\u043E\u043C <em>(asya bandhar\u016Bpatvam)</em>?<sup>2</sup>|</p><p>\u042D\u0442\u043E <em>(etad)</em> \u043F\u0440\u0430\u0432\u0434\u0430 <em>(satyam)</em>, \u0435\u0441\u043B\u0438 <em>(yadi)</em>, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043C\u0438\u043B\u043E\u0441\u0442\u0438 <em>(pras\u0101d\u0101t)</em> \u0412\u0441\u0435\u0432\u044B\u0448\u043D\u0435\u0433\u043E <em>(parama)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(\u012B\u015Bvara)</em>, \u043C\u043E\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u0431\u044B \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u0442\u044C <em>(pratyabhij\xF1\u0101yeta)</em> \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em> --\u0442.\u0435. \u0441\u043E\u0437\u043D\u0430\u0432\u0430\u0442\u044C, \u0447\u0442\u043E \u0434\u0430\u0436\u0435 \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0435 \u0443\u043C\u043E\u043C \u0437\u043D\u0430\u043D\u0438\u0435 \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043E \u0441\u0432\u0435\u0442\u043E\u043C--. \u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u0438\u0437-\u0437\u0430 \u0415\u0433\u043E m\u0101y\u0101\u015Bakti <em>(tad-m\u0101y\u0101\u015Baktita\u1E25)</em><sup>3</sup> \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na)</em> \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(vimar\u015Ba\u1E25)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0435 \u044D\u0442\u043E\u043C\u0443 <em>(evam)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>\u2014</p><blockquote><p><strong>\u041D\u0435-\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435 <em>(aviveka\u1E25)</em> [\u0442\u0430\u043A\u0438\u0445] \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u0432 <em>(tattv\u0101n\u0101m)</em> \u043A\u0430\u043A Kal\u0101 <em>(kal\u0101)</em> \u0438 \u0442.\u0434. <em>(\u0101d\u012Bn\u0101m)</em> [\u0435\u0441\u0442\u044C] \u041C\u0430\u0439\u044F <em>(m\u0101y\u0101)</em>||3||</strong></p></blockquote><p>\u042D\u0442\u043E <em>(ayam)</em> \u043D\u0435-\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435 <em>(aviveka\u1E25)</em> \u0442\u0430\u0442\u0442\u0432, \u0438\u043B\u0438 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u0432 <em>(tattv\u0101n\u0101m)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 Kal\u0101 --\u0442\u0430\u0442\u0442\u0432\u0430 7-- <em>(kal\u0101-\u0101di)</em> \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0437\u0435\u043C\u043B\u0435\u0439 --\u0442\u0430\u0442\u0442\u0432\u0430 36-- <em>(k\u1E63iti-ant\u0101n\u0101m)</em> \u2014\u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 <em>(r\u016Bpa)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0439 <em>(ki\xF1cid)</em> \u0434\u0435\u044F\u0442\u0435\u043B\u044C <em>(kart\u1E5Bt\u0101)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>\u2014 \u043A\u043B\u0430\u0441\u0441\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0445 <em>(avasthit\u0101n\u0101m)</em> \u043A\u0430\u043A \u041A\u0430\u043D\u0447\u0443\u043A\u0438 (Ka\xF1cuka-s), \u043F\u0443\u0440\u044C\u044F\u0448\u0442\u0430\u043A\u0430 (purya\u1E63\u1E6Daka) [\u0438] \u0433\u0440\u0443\u0431\u043E\u0435 \u0442\u0435\u043B\u043E <em>(ka\xF1cuka-purya\u1E63\u1E6Daka-sth\u016Bladehatvena)</em><sup>4</sup>, \u0438 \u043A\u043E\u0442\u043E\u0440\u043E\u0435 --\u0442.\u0435. \u043D\u0435-\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435-- <em>(ya\u1E25)</em> [\u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437] \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F <em>(pratipatti\u1E25)</em> \u043A\u0430\u043A \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 <em>(ap\u1E5Bthak-\u0101tmatvena)</em> \u044D\u0442\u0438\u0445 [\u0442\u0430\u0442\u0442\u0432], \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F <em>(abhimat\u0101n\u0101m eva)</em> \u043A\u0430\u043A \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0435 <em>(p\u1E5Bthaktva)</em>, [\u0435\u0441\u0442\u044C] M\u0101y\u0101 <em>(s\u0101 m\u0101y\u0101)</em>, [\u0438\u043B\u0438] \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u044F --\u0442.\u0435. \u0442\u0430\u0442\u0442\u0432\u0430 6-- <em>(prapa\xF1ca\u1E25)</em>, \u043F\u043E\u043B\u043D\u0430\u044F <em>(maya\u1E25)</em> \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F <em>(akhy\u0101ti)</em> \u043E \u0412\u044B\u0441\u0448\u0435\u043C \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0435 <em>(tattva)</em>|</p><p>\u042D\u0442\u043E <em>(tad)</em> \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Tantrasadbh\u0101va <em>(\u015Br\u012B-tantrasadbh\u0101ve)</em>:</p><blockquote><p>&quot;\u042D\u0442\u043E\u0442 [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0439 \u0438\u043D\u0434\u0438\u0432\u0438\u0434] <em>(asau)</em> \u0438\u043C\u0435\u0435\u0442 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(caitanya\u1E25)</em>, \u043E\u0445\u0432\u0430\u0447\u0435\u043D\u043D\u043E\u0435 <em>(udvalita)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C Kal\u0101 <em>(kal\u0101)</em>, \u043E\u0431\u044A\u0435\u043A\u0442\u044B \u0435\u0433\u043E \u0447\u0443\u0432\u0441\u0442\u0432 <em>(gocara\u1E25)</em> \u043E\u0442\u043E\u0431\u0440\u0430\u0436\u0430\u044E\u0442\u0441\u044F <em>(dar\u015Bita)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F Vidy\u0101 <em>(vidy\u0101)</em>; \u043E\u043D \u043E\u043A\u0440\u0430\u0448\u0435\u043D --\u0442.\u0435. [\u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E] \u0437\u0430\u0442\u0440\u043E\u043D\u0443\u0442-- <em>(ra\xF1jita-\u0101tm\u0101)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0439 \u0432\u043E\u043B\u0438 R\u0101ga <em>(r\u0101ge\u1E47a)</em>, [\u0438] \u043D\u0430\u0434\u0435\u043B\u0435\u043D <em>(yuta\u1E25)</em> \u043E\u0440\u0433\u0430\u043D\u0430\u043C\u0438 <em>(kara\u1E47ai\u1E25)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F <em>(buddhi)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u043C\u0430\u0439\u0438\u0447\u0435\u0441\u043A\u043E\u0435 <em>(m\u0101y\u0101-\u0101tmaka\u1E25)</em> \u0440\u0430\u0431\u0441\u0442\u0432\u043E <em>(bandha\u1E25)</em>, \u043A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(prokta\u1E25)</em>, \u0433\u043E\u0440\u0435\u0441\u0442\u043D\u043E <em>(dara-\u0101tmaka\u1E25)</em> \u0434\u043B\u044F \u043D\u0435\u0433\u043E <em>(tasya)</em>. \u041A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F <em>(sam\u0101satas)</em>, \u0413\u0443\u043D\u044B (Gu\u1E47a-s) --\u0420\u0430\u0434\u0436\u0430\u0441 (Rajas), \u0421\u0430\u0442\u0442\u0432\u0430 (Sattva) \u0438 \u0422\u0430\u043C\u0430\u0441 (Tamas)-- <em>(gu\u1E47a\u1E25)</em> \u0437\u0430\u0432\u0438\u0441\u044F\u0442 <em>(\u0101\u015Braya)</em> \u043E\u0442 \u044D\u0442\u043E\u0433\u043E --\u0442.\u0435. \u043E\u0442 M\u0101y\u0101-- <em>(tad)</em>, \u0430 \u0442\u0430\u043A\u0436\u0435 <em>(ca eva)</em> \u043F\u0440\u0430\u0432\u0435\u0434\u043D\u0430\u044F \u0438 \u043D\u0435\u043F\u0440\u0430\u0432\u0435\u0434\u043D\u0430\u044F \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(dharma\u1E25 adharma\u1E25)</em> [\u0437\u0430\u0432\u0438\u0441\u044F\u0442 \u043E\u0442 M\u0101y\u0101]. \u041F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 <em>(sa\u1E41sthita\u1E25)</em> \u0432 \u044D\u0442\u043E\u043C [M\u0101y\u0101] <em>(tatra)</em>, \u043E\u043D <em>(asau)</em> \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u0440\u0430\u0431\u0441\u0442\u0432\u0435 <em>(p\u0101\u015Bya\u1E25)</em>, [\u0438] \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F <em>(ti\u1E63\u1E6Dhati)</em> \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u043C <em>(p\u0101\u015Bita\u1E25)</em> \u044D\u0442\u0438\u043C\u0438 [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u043C\u0438 \u0432\u0435\u0449\u0430\u043C\u0438] <em>(tai\u1E25)</em>, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(tu... iti)</em>&quot;|</p></blockquote><p>\u0412 Spandak\u0101rik\u0101-s <em>(spande tu)</em> \u044D\u0442\u043E [\u0443\u0447\u0435\u043D\u0438\u0435] <em>(etad)</em> \u0431\u044B\u043B\u043E \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043E <em>(uktam)</em> \u043A\u043E\u0441\u0432\u0435\u043D\u043D\u043E <em>(bha\u1E45gy\u0101)</em> \u0447\u0435\u0440\u0435\u0437 \u044D\u0442\u0443 [\u043F\u0435\u0440\u0432\u0443\u044E \u0441\u0442\u0440\u043E\u043A\u0443 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430] <em>(anena)</em>:</p><blockquote><p>&quot;\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, \u044D\u0442\u0438 [\u0441\u0430\u043C\u044B\u0435 \u044D\u043C\u0430\u043D\u0430\u0446\u0438\u0438 \u0421\u043F\u0430\u043D\u0434\u044B] <em>(ete)</em>, \u0440\u0430\u0431\u043E\u0442\u0430\u044F \u043D\u0435\u0443\u0441\u0442\u0430\u043D\u043D\u043E \u0438 \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E <em>(udyat\u0101\u1E25)</em>, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043A\u0440\u044B\u0442\u044C, \u0438\u043B\u0438 \u0437\u0430\u0432\u0443\u0430\u043B\u0438\u0440\u043E\u0432\u0430\u0442\u044C <em>(sthagana)</em> \u0438\u0445 --\u0442.\u0435. \u043B\u044E\u0434\u0435\u0439 \u0441 \u043D\u0435\u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u044B\u043C \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u043E\u043C-- <em>(sva)</em> [\u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0435] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0438\u043B\u0438 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(sthiti)</em>, [\u0441\u043B\u0443\u0436\u0430\u0442 \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439] [\u043F\u0430\u0434\u0435\u043D\u0438\u044F] \u043B\u044E\u0434\u0435\u0439 \u0441 \u043D\u0435\u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u044B\u043C \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u043E\u043C <em>(aprabuddha-dhiya\u1E25... iti)</em>&quot;|<br> [\u0421\u043C. Spandak\u0101rik\u0101-s I, 20]</p></blockquote><p>||3||</p><hr><ol><li><p>\u0414\u0440\u0443\u0433\u043E\u0439 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0434\u043B\u044F prak\u0101\u015Baka \u2014 \u044D\u0442\u043E &quot;\u043E\u0442\u043A\u0440\u044B\u0432\u0430\u044E\u0449\u0438\u0439&quot;, \u0438\u043B\u0438 \u0434\u0430\u0436\u0435 &quot;\u043E\u0442\u043A\u0440\u044B\u0432\u0430\u044E\u0449\u0438\u0439 \u0441\u0432\u0435\u0442&quot;. \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439 \u2014 \u044D\u0442\u043E \u043D\u0435 \u043A\u0442\u043E \u0438\u043D\u043E\u0439, \u043A\u0430\u043A \u0101tm\u0101, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u0441\u0432\u0435\u0442&quot;, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0442\u043E\u0442, \u043A\u0442\u043E \u043F\u0440\u043E\u043B\u0438\u0432\u0430\u0435\u0442 \u0441\u0432\u0435\u0442 \u043D\u0435 \u043E\u0442\u043B\u0438\u0447\u0430\u0435\u0442\u0441\u044F \u043E\u0442 \u0441\u0430\u043C\u043E\u0433\u043E \u0441\u0432\u0435\u0442\u0430. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0437\u043D\u0430\u043D\u0438\u0435 (\u0441\u0432\u0435\u0442) \u0438 \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439 (\u0434\u0430\u044E\u0449\u0438\u0439 \u0441\u0432\u0435\u0442) \u0432\u0441\u0435\u0433\u0434\u0430 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043E\u0434\u043D\u0438\u043C \u0438 \u0442\u0435\u043C \u0436\u0435.</p></li><li><p>\u0414\u043B\u044F \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432: \u0424\u0440\u0430\u0437\u0430 &quot;kathamasya bandhar\u016Bpatvam&quot; \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u041A\u0430\u043A (katham) \u044D\u0442\u043E\u0433\u043E --\u0442.\u0435. \u0435\u0433\u043E-- (asya) \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043D\u0430\u043B\u0438\u0447\u0438\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u044B \u0440\u0430\u0431\u0441\u0442\u0432\u0430 (bandhar\u016Bpatvam)?&quot;. \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u044F \u043D\u0435 \u043C\u043E\u0433\u0443 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u0442\u044C \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043E\u0445!</p></li><li><p>\u041C\u0430\u0439\u044F\u0448\u0430\u043A\u0442\u0438 (M\u0101y\u0101\u015Bakti) (\u0431\u0443\u043A\u0432. \u043C\u0430\u0439\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0441\u0438\u043B\u0430) \u2014 \u043D\u0435 \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435, \u0447\u0442\u043E \u041C\u0430\u0439\u044F\u0442\u0430\u0442\u0442\u0432\u0430 (M\u0101y\u0101tattva) (\u0438\u043B\u0438 \u043F\u0440\u043E\u0441\u0442\u043E M\u0101y\u0101), \u0448\u0435\u0441\u0442\u0430\u044F \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u043A\u0430\u043A \u0443\u0447\u0438\u0442 \u0422\u0440\u0438\u043A\u0430. \u041D\u0435\u0442! M\u0101y\u0101\u015Bakti \u0435\u0441\u0442\u044C \u0415\u0433\u043E \u0441\u0438\u043B\u0430 \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439 (\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438), \u0433\u0434\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0432\u0435\u0447\u043D\u043E\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0415\u0433\u043E \u0431\u043B\u0430\u0433\u043E\u0432\u043E\u043B\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 pras\u0101da \u2014 \u044D\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u0443\u0434\u0430\u043B\u0435\u043D\u0438\u0435 \u0418\u043C m\u0101y\u0101\u015Bakti, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u043D\u0435\u043E\u0442\u044A\u0435\u043C\u043B\u0435\u043C\u043E\u0435 \u043B\u0435\u0436\u0430\u0449\u0435\u0435 \u0432 \u043E\u0441\u043D\u043E\u0432\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0435\u0441\u043B\u0438 \u043A\u0442\u043E-\u0442\u043E \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0435\u0442\u0441\u044F \u0415\u0433\u043E \u041C\u0438\u043B\u043E\u0441\u0442\u044C\u044E, \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0435 \u0443\u043C\u043E\u043C \u0437\u043D\u0430\u043D\u0438\u0435 \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u0441\u043C\u043E\u0436\u0435\u0442 \u0441\u0432\u044F\u0437\u0430\u0442\u044C \u0435\u0433\u043E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0442\u0430\u043A\u043E\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442, \u0447\u0442\u043E \u0434\u0430\u0436\u0435 \u0442\u0430\u043A\u043E\u0435 \u0443\u0431\u043E\u0433\u043E\u0435 \u0437\u043D\u0430\u043D\u0438\u0435 \u0442\u0430\u043A\u0436\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0432\u0435\u0442\u043E\u043C. \u0421\u0432\u043E\u0431\u043E\u0434\u0430 \u0438 \u0440\u0430\u0431\u0441\u0442\u0432\u043E, \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043E\u0442\u043D\u043E\u0441\u044F\u0442\u0441\u044F \u043A \u0443\u0434\u0430\u043B\u0435\u043D\u0438\u044E \u0418\u043C \u041C\u0430\u0439\u044F\u0448\u0430\u043A\u0442\u0438 (m\u0101y\u0101\u015Bakti) \u0438\u043B\u0438 \u043A \u0435\u0435 \u043D\u0430\u043B\u0438\u0447\u0438\u044E. \u041E\u0447\u0435\u043D\u044C \u043F\u0440\u043E\u0441\u0442\u043E!</p></li><li><p>Kal\u0101 \u2014 \u044D\u0442\u043E \u0441\u0435\u0434\u044C\u043C\u0430\u044F \u0442\u0430\u0442\u0442\u0432\u0430 (\u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F, \u0438\u043B\u0438 \u043F\u0440\u0438\u043D\u0446\u0438\u043F) \u0432 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u043C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0438. \u041F\u0440\u0438\u0440\u043E\u0434\u0430 Kal\u0101 \u2014 \u044D\u0442\u043E \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0430\u044F \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u0434\u0435\u0439\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C. \u041F\u043E\u0434 &quot;\u0438 \u0442.\u0434.&quot;, \u0430\u0432\u0442\u043E\u0440 \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0442\u0430\u0442\u0442\u0432 (\u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 8-\u0439 \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F 36-\u0439 -\u0437\u0435\u043C\u043B\u0435\u0439--). \u041A\u0430\u043D\u0447\u0443\u043A\u0438 (Ka\xF1cuka-s) \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043E\u0431\u043E\u043B\u043E\u0447\u043A\u0430\u043C\u0438 \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A purya\u1E63\u1E6Daka \u2014 \u044D\u0442\u043E \u0442\u043E\u043D\u043A\u043E\u0435 \u0442\u0435\u043B\u043E, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437 \u0431\u0443\u0434\u0434\u0445\u0438 (\u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430), \u0430\u0445\u0430\u043D\u043A\u0430\u0440\u044B (aha\u1E45k\u0101ra), \u0438\u043B\u0438 \u044D\u0433\u043E, \u043C\u0430\u043D\u0430\u0441\u0430 (\u043E\u0431\u044B\u0447\u043D\u043E\u0433\u043E \u0443\u043C\u0430) \u0438 \u043F\u044F\u0442\u0438 \u0422\u0430\u043D\u043C\u0430\u0442\u0440 (Tanm\u0101tra-s) \u2014 \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 \u043E\u0442 \u0442\u0430\u0442\u0442\u0432\u044B 27 \u0434\u043E \u0442\u0430\u0442\u0442\u0432\u044B 31.</p></li></ol></div><div class="stanza"><a href="#s3.4" id="s3.4" class="num">3.4</a><div class="sans"><p>\u0905\u0924\u0936\u094D\u091A\u0948\u0924\u0924\u094D\u092A\u094D\u0930\u0936\u092E\u093E\u092F\u2014</p><blockquote><p><strong>\u0936\u0930\u0940\u0930\u0947 \u0938\u0902\u0939\u093E\u0930\u0903 \u0915\u0932\u093E\u0928\u093E\u092E\u094D\u0965\u096A\u0965</strong></p></blockquote><p>\u092E\u0939\u093E\u092D\u0942\u0924\u093E\u0924\u094D\u092E\u0915\u0902 \u092A\u0941\u0930\u094D\u092F\u0937\u094D\u091F\u0915\u0930\u0942\u092A\u0902 \u0938\u092E\u0928\u093E\u0928\u094D\u0924\u0902 \u092F\u0924\u094D\u0938\u094D\u0925\u0942\u0932\u0902 \u0938\u0941\u0915\u094D\u0937\u094D\u092E\u0902 \u092A\u0930\u0902 \u0936\u0930\u0940\u0930\u0902 \u0924\u0924\u094D\u0930 \u092F\u093E\u0903 \u092A\u0943\u0925\u093F\u0935\u094D\u092F\u093E\u0926\u093F\u0936\u093F\u0935\u093E\u0928\u094D\u0924\u0924\u0924\u094D\u0924\u094D\u0935\u0930\u0942\u092A\u093E\u0903 \u0915\u0932\u093E \u092D\u093E\u0917\u093E\u0938\u094D\u0924\u093E\u0938\u093E\u0902 \u0938\u0902\u0939\u093E\u0930\u0903 \u0938\u094D\u0935\u0915\u093E\u0930\u0923\u0947 \u0932\u092F\u092D\u093E\u0935\u0928\u092F\u093E \u0926\u093E\u0939\u093E\u0926\u093F\u091A\u093F\u0928\u094D\u0924\u0928\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u0935\u093E \u0927\u094D\u092F\u093E\u0924\u0935\u094D\u092F \u0907\u0924\u093F \u0936\u0947\u0937\u0903\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u092D\u0941\u0935\u0928\u093E\u0927\u094D\u0935\u093E\u0926\u093F\u0930\u0942\u092A\u0947\u0923 \u091A\u093F\u0928\u094D\u0924\u092F\u0947\u0924\u094D\u0915\u094D\u0930\u092E\u0936\u094B\u093D\u0916\u093F\u0932\u092E\u094D\u0964<br> \u0938\u094D\u0925\u0942\u0932\u0938\u0942\u0915\u094D\u0937\u094D\u092E\u092A\u0930\u0938\u094D\u0925\u093F\u0924\u094D\u092F\u093E \u092F\u093E\u0935\u0926\u0928\u094D\u0924\u0947 \u092E\u0928\u094B\u0932\u092F\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0924\u0925\u093E</p><blockquote><p>\u0915\u093E\u0932\u093E\u0917\u094D\u0928\u093F\u0928\u093E \u0915\u093E\u0932\u092A\u0926\u093E\u0926\u0941\u0924\u094D\u0925\u093F\u0924\u0947\u0928 \u0938\u094D\u0935\u0915\u0902 \u092A\u0941\u0930\u092E\u094D\u0964<br> \u092A\u094D\u0932\u0941\u0937\u094D\u091F\u0902 \u0935\u093F\u091A\u093F\u0928\u094D\u0924\u092F\u0947\u0926\u0928\u094D\u0924\u0947 \u0936\u093E\u0928\u094D\u0924\u093E\u092D\u093E\u0938\u0903 \u092A\u094D\u0930\u091C\u093E\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u090F\u0935\u092E\u093E\u0926\u093F \u091A \u0938\u0930\u094D\u0935\u093E\u0917\u092E\u0947\u0937\u094D\u0935\u0938\u094D\u0924\u093F\u0964 \u0905\u0924 \u090F\u0935</p><blockquote><p>\u0909\u091A\u094D\u091A\u093E\u0930\u0915\u0930\u0923\u0927\u094D\u092F\u093E\u0928\u0935\u0930\u094D\u0923\u0938\u094D\u0925\u093E\u0928\u092A\u094D\u0930\u0915\u0932\u094D\u092A\u0928\u0948\u0903\u0964<br> \u092F\u094B \u092D\u0935\u0947\u0924\u094D\u0938 \u0938\u092E\u093E\u0935\u0947\u0936\u0903 \u0938\u092E\u094D\u092F\u0917\u093E\u0923\u0935 \u0909\u091A\u094D\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u092A\u0942\u0930\u094D\u0935\u0936\u093E\u0938\u094D\u0924\u094D\u0930\u0947 \u0927\u094D\u092F\u093E\u0928\u093E\u0926\u094D\u092F\u0947\u0935\u093E\u0923\u0935\u0924\u094D\u0935\u0947\u0928\u094B\u0915\u094D\u0924\u092E\u094D\u0964 \u090F\u0924\u091A\u094D\u091A \u0938\u094D\u0925\u0942\u0932\u0924\u094D\u0935\u093E\u0924\u094D\u0936\u093E\u0915\u094D\u0924\u094B\u092A\u093E\u092F\u092A\u094D\u0930\u0915\u093E\u0936\u093E\u0924\u094D\u092E\u0928\u093F \u0938\u094D\u092A\u0928\u094D\u0926\u0936\u093E\u0938\u094D\u0924\u094D\u0930\u0947 \u0928 \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0964 \u092F\u0924\u094D\u0924\u094D\u0935\u0924\u094D\u0930 \u092A\u0930\u094D\u092F\u0935\u0938\u093E\u0928\u092D\u0919\u094D\u0917\u094D\u092F\u093E \u0936\u093E\u0915\u094D\u0924\u093E\u0926\u094D\u092F\u0938\u094D\u0924\u093F \u0924\u0926\u0938\u094D\u092E\u093E\u092D\u093F\u0930\u0924\u094D\u0930\u093E\u092A\u093F \u0938\u094D\u092A\u0928\u094D\u0926\u0917\u094D\u0930\u0928\u094D\u0925\u093E\u0924\u094D\u0938\u0902\u0935\u093E\u0926\u093F\u0924\u0902 \u0938\u0902\u0935\u093E\u0926\u092F\u093F\u0937\u094D\u092F\u0924\u0947 \u091A \u0915\u093F\u091E\u094D\u091A\u093F\u0924\u094D\u0965\u096A\u0965</p></div><div class="trans"><p>Ata\u015Bcaitatpra\u015Bam\u0101ya\u2014</p><blockquote><p><strong>\u015Aar\u012Bre sa\u1E41h\u0101ra\u1E25 kal\u0101n\u0101m||4||</strong></p></blockquote><p>Mah\u0101bh\u016Bt\u0101tmaka\u1E41 purya\u1E63\u1E6Dakar\u016Bpa\u1E41 saman\u0101nta\u1E41 yatsth\u016Bla\u1E41 suk\u1E63ma\u1E41 para\u1E41 \u015Bar\u012Bra\u1E41 tatra y\u0101\u1E25 p\u1E5Bthivy\u0101di\u015Biv\u0101ntatattvar\u016Bp\u0101\u1E25 kal\u0101 bh\u0101g\u0101st\u0101s\u0101\u1E41 sa\u1E41h\u0101ra\u1E25 svak\u0101ra\u1E47e layabh\u0101vanay\u0101 d\u0101h\u0101dicintanayukty\u0101 v\u0101 dhy\u0101tavya iti \u015Be\u1E63a\u1E25| Yadukta\u1E41 \u015Br\u012Bvij\xF1\u0101nabhairave</p><blockquote><p>Bhuvan\u0101dhv\u0101dir\u016Bpe\u1E47a cintayetkrama\u015Bo&#39;khilam|<br> Sth\u016Blas\u016Bk\u1E63maparasthity\u0101 y\u0101vadante manolaya\u1E25||</p></blockquote><p>iti| Tath\u0101</p><blockquote><p>K\u0101l\u0101gnin\u0101 k\u0101lapad\u0101dutthitena svaka\u1E41 puram|<br> Plu\u1E63\u1E6Da\u1E41 vicintayedante \u015B\u0101nt\u0101bh\u0101sa\u1E25 praj\u0101yate||</p></blockquote><p>iti| Evam\u0101di ca sarv\u0101game\u1E63vasti| Ata eva</p><blockquote><p>Ucc\u0101rakara\u1E47adhy\u0101navar\u1E47asth\u0101naprakalpanai\u1E25|<br> Yo bhavetsa sam\u0101ve\u015Ba\u1E25 samyag\u0101\u1E47ava ucyate||</p></blockquote><p>iti \u015Br\u012Bp\u016Brva\u015B\u0101stre dhy\u0101n\u0101dyev\u0101\u1E47avatvenoktam| Etacca sth\u016Blatv\u0101t\u015B\u0101ktop\u0101yaprak\u0101\u015B\u0101tmani spanda\u015B\u0101stre na sa\u1E45g\u1E5Bh\u012Btam| Yattvatra paryavas\u0101nabha\u1E45gy\u0101 \u015B\u0101kt\u0101dyasti tadasm\u0101bhiratr\u0101pi spandagranth\u0101tsa\u1E41v\u0101dita\u1E41 sa\u1E41v\u0101dayi\u1E63yate ca ki\xF1cit||4||</p></div><p>\u041F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(atas ca)</em>, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u043E\u0436\u0438\u0442\u044C \u043A\u043E\u043D\u0435\u0446 <em>(pra\u015Bam\u0101ya)</em> \u044D\u0442\u043E\u043C\u0443 [\u0440\u0430\u0431\u0441\u0442\u0432\u0443] <em>(etad)</em>\u2014</p><blockquote><p><strong>\u0420\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(sa\u1E41h\u0101ra\u1E25)</em> \u0447\u0430\u0441\u0442\u0435\u0439 <em>(kal\u0101n\u0101m)</em> --\u0442\u0430\u0442\u0442\u0432, \u0438\u043B\u0438 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u0432 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F-- \u0432 \u0442\u0435\u043B\u0435 --\u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u043C, \u0442\u043E\u043D\u043A\u043E\u043C, \u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u043C-- <em>(\u015Bar\u012Bre)</em> [\u0434\u043E\u043B\u0436\u043D\u043E \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C\u0441\u044F \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E Bh\u0101van\u0101, \u0438\u043B\u0438 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F]||4||</strong></p></blockquote><p>\u015Aar\u012Bra --\u0431\u0443\u043A\u0432. \u0442\u0435\u043B\u043E-- <em>(\u015Bar\u012Bram)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0437\u0434\u0435\u0441\u044C] \u0433\u0440\u0443\u0431\u043E\u0435 [\u0442\u0435\u043B\u043E] <em>(sth\u016Blam)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(yad)</em> \u0441\u043E\u0441\u0442\u043E\u0438\u0442 <em>(\u0101tmakam)</em> \u0438\u0437 \u0432\u0435\u043B\u0438\u043A\u0438\u0445 <em>(mah\u0101)</em> \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(bh\u016Bta)</em> --\u0438\u043B\u0438 \u0442\u0430\u0442\u0442\u0432 \u0441 32-\u0439 \u0434\u043E 36-\u0439--, \u0442\u043E\u043D\u043A\u043E\u0435 [\u0442\u0435\u043B\u043E] <em>(suk\u1E63ma)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(yad)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(r\u016Bpam)</em> \u043F\u0443\u0440\u044C\u044F\u0448\u0442\u0430\u043A\u043E\u0439 (purya\u1E63\u1E6Daka) <em>(purya\u1E63\u1E6Daka)</em> --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442, \u044D\u0433\u043E, \u043E\u0431\u044B\u0447\u043D\u044B\u0439 \u0443\u043C \u0438 \u0422\u0430\u043D\u043C\u0430\u043D\u0442\u0440\u044B (Tanm\u0101tra-s)--, [\u0438] \u0432\u044B\u0441\u0448\u0435\u0435 [\u0442\u0435\u043B\u043E] --\u0442.\u0435. \u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0435 (\u043F\u0440\u0438\u0447\u0438\u043D\u043D\u043E\u0435)-- <em>(param)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(yad)</em> \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(antam)</em> \u0432 Saman\u0101 <em>(saman\u0101)</em> --\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u0442\u0435\u043B\u043E, \u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439 \u0438 \u0442\u043E\u043D\u043A\u0438\u043C \u0443\u043C\u043E\u043C \u0432\u043F\u043B\u043E\u0442\u044C \u0434\u043E Saman\u0101, \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u044F\u044F \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0441\u043E\u0431\u043E\u0439 \u0428\u0430\u043A\u0442\u0438, \u0438\u043B\u0438 \u0421\u0438\u043B\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u0430, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0443\u044E \u0441\u0435\u0431\u044F \u043A\u0430\u043A \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435 \u043E\u0442 \u015B\u016Bnya, \u0438\u043B\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043F\u0443\u0441\u0442\u043E\u0442\u044B \u0434\u043E \u0442\u0430\u0442\u0442\u0432\u044B 36--. \u0412 \u044D\u0442\u043E\u043C [\u015Bar\u012Bra, \u0438\u043B\u0438 \u0442\u0435\u043B\u0435] <em>(tatra)</em> \u044D\u0442\u0438 <em>(y\u0101\u1E25)</em> kal\u0101-s <em>(kal\u0101\u1E25)</em>, [\u0438\u043B\u0438] \u0447\u0430\u0441\u0442\u0438 <em>(bh\u0101g\u0101\u1E25)</em> \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(r\u016Bp\u0101\u1E25)</em> \u0442\u0430\u0442\u0442\u0432\u0430\u043C\u0438 --\u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0430\u043C\u0438, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F\u043C\u0438-- <em>(tattva)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>(\u0101di)</em> \u0437\u0435\u043C\u043B\u0438 -- \u0432 \u0442\u0430\u0442\u0442\u0432\u0435 36-- <em>(p\u1E5Bthiv\u012B)</em> [\u0438] \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0432 <em>(anta)</em> \u015Aiva <em>(\u015Biva)</em>. \u0420\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(sa\u1E41h\u0101ra\u1E25)</em> \u044D\u0442\u0438\u0445 [\u0447\u0430\u0441\u0442\u0435\u0439] <em>(t\u0101s\u0101m)</em> \u0432 \u0438\u0445 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u043F\u0440\u0438\u0447\u0438\u043D\u0430\u0445 <em>(sva-k\u0101ra\u1E47e)</em> \u0434\u043E\u043B\u0436\u043D\u043E \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0442\u044C\u0441\u044F \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438 <em>(dhy\u0101tavya\u1E25)</em>, [\u0431\u0443\u0434\u044C \u0442\u043E] \u0447\u0435\u0440\u0435\u0437 Bh\u0101van\u0101 --\u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0435 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435-- <em>(bh\u0101vanay\u0101)</em> \u043D\u0430 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0438 [\u043A\u0430\u0436\u0434\u043E\u0439 \u0442\u0430\u0442\u0442\u0432\u044B \u0432 \u043F\u0440\u0435\u0434\u0448\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0439] <em>(laya)</em>, \u0438\u043B\u0438 <em>(v\u0101)</em> \u0447\u0435\u0440\u0435\u0437 <em>(yukty\u0101)</em> \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435 <em>(cintana)</em> \u043E \u0441\u0436\u0438\u0433\u0430\u043D\u0438\u0438 <em>(d\u0101ha)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>--.. \u042D\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0434\u043E\u0431\u0430\u0432\u043B\u0435\u043D\u043E [\u0432 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u0434\u043B\u044F \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F \u0441\u043C\u044B\u0441\u043B\u0430] <em>(iti \u015Be\u1E63a\u1E25)</em>|</p><p>\u042D\u0442\u043E <em>(yad)</em> \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Vij\xF1\u0101nabhairava <em>(\u015Br\u012B-vij\xF1\u0101nabhairave)</em>:</p><blockquote><p>&quot;\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0434\u0443\u043C\u0430\u0442\u044C <em>(cintayet)</em> \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E --\u0442.\u0435. \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E-- <em>(krama\u015Bas)</em> \u043F\u0440\u043E \u0432\u0441\u044E [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E] <em>(akhilam)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0443\u044E\u0441\u044F \u043A\u0430\u043A <em>(r\u016Bpe\u1E47a)</em> Bhuvan\u0101dhv\u0101 <em>(bhuvana-adhv\u0101)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u043E\u0441\u0442\u0430\u0432\u0430\u044F\u0441\u044C <em>(sthity\u0101)</em> \u0432 \u0433\u0440\u0443\u0431\u043E\u043C, \u0442\u043E\u043D\u043A\u043E\u043C \u0438 \u043F\u0440\u0438\u0447\u0438\u043D\u043D\u043E\u043C (\u0442\u0435\u043B\u0430\u0445) --\u0442.\u0435. \u0447\u0435\u0440\u0435\u0437 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u043E\u0434\u043D\u043E\u0433\u043E \u0432 \u0434\u0440\u0443\u0433\u043E\u043C-- <em>(sth\u016Bla-s\u016Bk\u1E63ma-para)</em>, \u043F\u043E\u043A\u0430 <em>(y\u0101vat)</em> [\u043D\u0435 \u043F\u0440\u043E\u0438\u0437\u043E\u0439\u0434\u0435\u0442], \u043D\u0430\u043A\u043E\u043D\u0435\u0446 <em>(ante)</em>, \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(laya)</em> \u0443\u043C\u0430 <em>(manas... iti)</em>&quot;||</p></blockquote><p>\u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em>:</p><blockquote><p>&quot;\u041D\u0430\u0434\u043E \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u0442\u044C <em>(vicintayet)</em>, \u0447\u0442\u043E \u0432\u0430\u0448\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(svakam)</em> \u0442\u0435\u043B\u043E <em>(puram)</em> \u0431\u044B\u043B\u043E \u0441\u043E\u0436\u0436\u0435\u043D\u043E <em>(plu\u1E63\u1E6Dam)</em> \u043E\u0433\u043D\u0435\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0438 K\u0101l\u0101gni <em>(k\u0101la-agnin\u0101)</em>, \u043F\u043E\u0434\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u043C\u0441\u044F <em>(utthitena)</em> \u043E\u0442 \u0431\u043E\u043B\u044C\u0448\u043E\u0433\u043E \u043F\u0430\u043B\u044C\u0446\u0430 \u043F\u0440\u0430\u0432\u043E\u0439 \u043D\u043E\u0433\u0438 <em>(k\u0101lapad\u0101t)</em>. \u0418 \u0432 \u043A\u043E\u043D\u0446\u0435 <em>(ante)</em>, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(praj\u0101yate... iti)</em> \u0441\u0432\u0435\u0442 <em>(\u0101bh\u0101sa\u1E25)</em> \u015A\u0101nta --\u0431\u0443\u043A\u0432. \u041C\u0438\u0440\u043D\u044B\u0439, \u0442.\u0435. \u0428\u0438\u0432\u0430-- <em>(ante)</em> <sup>1</sup>&quot;||</p></blockquote><p>\u0422\u0430\u043A\u043E\u0435 [\u043E\u043F\u0438\u0441\u0430\u043D\u0438\u0435 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F] <em>(evam-\u0101di ca)</em> \u0438\u043C\u0435\u0435\u0442\u0441\u044F <em>(asti)</em> \u0432\u043E \u0432\u0441\u0435\u0445 \u0100gama-s --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0445 \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u044F\u0445-- <em>(sarva-\u0101game\u1E63u)</em>|</p><p>\u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas eva)</em>, \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C P\u016Brva\u015B\u0101stra --i.e. M\u0101lin\u012Bvijayatantra-- <em>(\u015Br\u012B-p\u016Brva-\u015B\u0101stre)</em>, \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(uktam)</em> , \u0447\u0442\u043E dhy\u0101na <em>(dhy\u0101na)</em>, \u0438 \u0442.\u0434. <em>(\u0101di eva)</em> \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0101\u1E47ava --\u0442.\u0435. \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0442 \u043A \u0100\u1E47avop\u0101ya-- <em>(\u0101\u1E47avatvena)</em>:</p><blockquote><p>&quot;\u041F\u043E\u043B\u043D\u043E\u0435 <em>(sa\u1E25... samyak)</em> \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 \u0432 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435 <em>(sam\u0101ve\u015Ba\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(ya\u1E25)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(bhavet)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C Ucc\u0101ra, Kara\u1E47a, Dhy\u0101na, Var\u1E47a \u0438 Sth\u0101nakalpan\u0101 <em>(ucc\u0101ra-kara\u1E47a-dhy\u0101na-var\u1E47a-sth\u0101naprakalpanai\u1E25)</em>, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u043A\u0430\u043A <em>(ucyate)</em> \u0100\u1E47ava <em>(\u0101\u1E47ava\u1E25... iti)</em>&quot;||<br> [\u0421\u043C. II, 21 \u0432 M\u0101lin\u012Bvijaya]</p></blockquote><p>\u042D\u0442\u043E\u0442 [\u0442\u0438\u043F \u043C\u0435\u0442\u043E\u0434\u043E\u0432] --\u0442.\u0435. \u043C\u0435\u0442\u043E\u0434\u044B, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0438\u0435 \u0100\u1E47avop\u0101ya-- <em>(etad ca)</em>, \u0431\u0443\u0434\u0443\u0447\u0438 \u0433\u0440\u0443\u0431\u044B\u043C\u0438 <em>(sth\u016Blatv\u0101t)</em>, \u043D\u0435 \u0431\u044B\u043B\u0438 \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u044B <em>(na sa\u1E45g\u1E5Bh\u012Btam)</em> \u0432 Spanda\u015B\u0101stra --\u0442.\u0435. Spandak\u0101rik\u0101-s-- <em>(spanda-\u015B\u0101stre)</em>, \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u044E\u0449\u0438\u043C <em>(prak\u0101\u015Ba-\u0101tmani)</em> \u015A\u0101ktop\u0101ya <em>(\u015B\u0101ktop\u0101ya)</em> --\u043A\u043E\u0440\u043E\u0447\u0435, Spanda\u015B\u0101stra \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442 \u0432\u043E\u043F\u0440\u043E\u0441\u044B, \u043A\u0430\u0441\u0430\u044E\u0449\u0438\u0435\u0441\u044F \u015A\u0101ktop\u0101ya--|</p><p>\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, \u0432\u0441\u0435 <em>(yad)</em>, \u0447\u0442\u043E \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u015A\u0101ktop\u0101ya <em>(\u015B\u0101kta)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043D\u0430\u0439\u0434\u0435\u043D\u043E <em>(asti)</em> \u0437\u0434\u0435\u0441\u044C <em>(atra)</em> \u043A\u0430\u043A \u0437\u0430\u0432\u0435\u0440\u0448\u0430\u044E\u0449\u0438\u0435 \u043C\u0435\u0442\u043E\u0434\u044B <em>(paryavas\u0101na-bha\u1E45gy\u0101)</em>, \u0447\u0442\u043E <em>(tad)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u0432 \u044D\u0442\u043E\u043C [\u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435] <em>(atra)</em> \u043D\u0430\u043C\u0438 <em>(asm\u0101bhi\u1E25)</em> \u0431\u044B\u043B\u043E \u0441\u0434\u0435\u043B\u0430\u043D\u043E \u0441\u043E\u0433\u043B\u0430\u0441\u043E\u0432\u0430\u043D\u043D\u044B\u043C [\u0441 \u0100\u1E47avop\u0101ya] <em>(sa\u1E41v\u0101ditam)</em> \u0438 \u043A\u043D\u0438\u0433\u043E\u0439 <em>(granth\u0101t)</em>, \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \u0421\u043F\u0430\u043D\u0434\u0435 <em>(spanda)</em> --\u0442.\u0435. \u0446\u0438\u0442\u0430\u0442\u0430\u043C\u0438, \u0438\u0437\u0432\u043B\u0435\u0447\u0435\u043D\u043D\u044B\u043C\u0438 \u0438\u0437 \u0441\u0430\u043C\u0438\u0445 Spandak\u0101rik\u0101-s--, \u0438 <em>(ca)</em> \u0431\u0443\u0434\u0435\u0442 \u0441\u0434\u0435\u043B\u0430\u043D\u043E \u0441\u043E\u0433\u043B\u0430\u0441\u043E\u0432\u0430\u043D\u043D\u044B\u043C <em>(sa\u1E41v\u0101dayi\u1E63yate)</em> [\u0432 \u0431\u0443\u0434\u0443\u0449\u0435\u043C \u0442\u0430\u043A\u0436\u0435] \u043D\u0435\u043C\u043D\u043E\u0433\u043E <em>(ki\xF1cid)</em>||4||</p><hr><ol><li><p>\u0422\u0435\u0440\u043C\u0438\u043D &quot;\u015A\u0101nta&quot; \u0442\u0430\u043A\u0436\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u041C\u0438\u0440&quot;. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0432 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0435 \u0435\u0441\u0442\u044C \u0442\u0430\u043A\u043E\u0439 \u0442\u0432\u0438\u0441\u0442. \u041D\u043E, \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0412\u044B\u0441\u0448\u0438\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0442\u0430\u043A\u0436\u0435 \u0435\u0441\u0442\u044C \u044D\u0442\u043E\u0442 \u041C\u0438\u0440. \u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u0432 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0432\u0435\u0440\u0441\u0438\u044F\u0445 Vij\xF1\u0101nabhairava, \u0437\u0430\u043A\u043B\u044E\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u0447\u0430\u0441\u0442\u044C \u0432\u0430\u0440\u044C\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u043E\u0442 &quot;praj\u0101yate&quot; (\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442) \u0434\u043E &quot;\u0924\u0926\u093E \u092D\u0935\u0947\u0924\u094D&quot; - &quot;tad\u0101 bhavet&quot; (\u0442\u043E\u0433\u0434\u0430, \u0438\u043C\u0435\u0435\u0442\u0441\u044F). \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0432\u0438\u0434\u043E\u0438\u0437\u043C\u0435\u043D\u044F\u0435\u0442\u0441\u044F \u043E\u043F\u044F\u0442\u044C: &quot;\u0422\u043E\u0433\u0434\u0430, \u043D\u0430\u043A\u043E\u043D\u0435\u0446, \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0432\u0441\u043F\u044B\u0448\u043A\u0430 \u041C\u0438\u0440\u0430&quot;. \u0417\u0434\u0435\u0441\u044C \u0432\u044B \u0438\u043C\u0435\u0435\u0442\u0435 \u044D\u0442\u043E... \u0432\u0430\u043C \u043D\u0435 \u0437\u0430\u0445\u043E\u0447\u0435\u0442\u0441\u044F \u0431\u044B\u0442\u044C \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0447\u0438\u043A\u043E\u043C \u043F\u043E\u0441\u043B\u0435 \u0432\u0441\u0435\u0433\u043E \u044D\u0442\u043E\u0433\u043E, \u0445\u0430\u0445\u0430. \u041A\u0440\u043E\u043C\u0435 \u0448\u0443\u0442\u043E\u043A, \u0438\u043D\u043E\u0433\u0434\u0430 \u044F \u0434\u0430\u0436\u0435 \u043C\u043E\u0433\u0443 \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0442\u044C \u043E\u043A\u043E\u043B\u043E \u0447\u0430\u0441\u0430 \u043D\u0430\u0434 \u0441\u0430\u043C\u044B\u043C \u0442\u043E\u0447\u043D\u044B\u043C/\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u043C \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435\u043C \u043E\u0434\u043D\u043E\u0433\u043E \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0442\u0435\u0440\u043C\u0438\u043D\u0430. \u041D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u0442\u0440\u0430\u043D\u043D\u044B\u0435 \u043F\u0430\u0440\u0430\u0433\u0440\u0430\u0444\u044B \u043C\u043E\u0433\u0443\u0442 \u0437\u0430\u043D\u0438\u043C\u0430\u0442\u044C \u0447\u0430\u0441\u044B, \u0438 \u043D\u0435 \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u044F \u043D\u0435 \u043F\u043E\u043D\u0438\u043C\u0430\u044E \u0441\u043C\u044B\u0441\u043B \u0431\u044B\u0441\u0442\u0440\u043E (\u0447\u0442\u0435\u043D\u0438\u0435 \u0421\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0430 \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u0440\u0443\u0434\u043D\u044B\u043C \u0434\u043B\u044F \u043C\u0435\u043D\u044F... \u0430 \u043E\u0431\u044B\u0447\u043D\u043E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043F\u043E \u043C\u0435\u043D\u044C\u0448\u0435\u0439 \u043C\u0435\u0440\u0435 \u0438\u043D\u043E\u0433\u0434\u0430 \u0442\u0435\u043A\u0441\u0442 \u2014 \u043D\u0430\u0441\u0442\u043E\u043B\u044C\u043A\u043E \u043A\u043E\u0448\u043C\u0430\u0440\u043D\u044B\u0439, \u0447\u0442\u043E \u044F \u0437\u0430\u0441\u0442\u0440\u0435\u0432\u0430\u044E \u043D\u0430 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u0440\u0435\u043C\u044F), \u0430 \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u0445\u043E\u0447\u0435\u0442\u0441\u044F \u0431\u044B\u0442\u044C \u043D\u0430\u0441\u0442\u043E\u043B\u044C\u043A\u043E \u0442\u043E\u0447\u043D\u044B\u043C/\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u044B\u043C, \u043D\u0430\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u044D\u0442\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E, \u0447\u0442\u043E\u0431\u044B \u0432 \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u0432\u0440\u0435\u043C\u044F \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u044C \u043C\u043E\u0433 \u0431\u044B \u043C\u0435\u043D\u044F \u043F\u043E\u043D\u044F\u0442\u044C. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0440\u0435\u0447\u044C \u0438\u0434\u0435\u0442 \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u043E \u0440\u0430\u0431\u043E\u0442\u0435 \u0441\u043E \u0441\u043B\u043E\u0432\u0430\u0440\u0435\u043C, \u043D\u043E, \u041E \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u044B\u0435! \u0447\u0442\u043E\u0431\u044B \u0443 \u0432\u0430\u0441 \u0432\u043E\u043B\u0448\u0435\u0431\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u0431\u044B\u043B \u0442\u043E\u0447\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434. \u041D\u0435 \u0442\u0430\u043A \u043B\u0438?</p><p>\u041F\u0435\u0440\u0432\u0430\u044F \u0438 \u043E\u0441\u043D\u043E\u0432\u043D\u0430\u044F \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0430 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u043A\u0430\u0436\u0434\u044B\u0439 \u0442\u0435\u0440\u043C\u0438\u043D \u043C\u043E\u0436\u0435\u0442 \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0442\u044C \u0433\u0438\u0433\u0430\u043D\u0442\u0441\u043A\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0439 \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0430\u043C\u0438, \u0438 \u0432\u0430\u043C, \u0432 \u043E\u0431\u0449\u0435\u043C, \u043F\u0440\u0438\u0434\u0435\u0442\u0441\u044F \u0432\u044B\u0431\u0438\u0440\u0430\u0442\u044C \u0442\u043E\u043B\u044C\u043A\u043E \u043E\u0434\u043D\u043E \u0438\u0437 \u043D\u0438\u0445. \u041D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u043D\u0435 \u043C\u043E\u0433\u0443\u0442 \u0431\u044B\u0442\u044C \u043D\u0430\u0439\u0434\u0435\u043D\u044B \u0432 &quot;\u043E\u0431\u044B\u0447\u043D\u043E\u043C&quot; \u0441\u043B\u043E\u0432\u0430\u0440\u0435, \u0438 \u0432\u0430\u043C \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043F\u0440\u0438\u0431\u0435\u0433\u0430\u0442\u044C \u043A \u0434\u0440\u0443\u0433\u0438\u043C \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430\u043C (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u043A \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F\u043C \u043D\u0430 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435 \u0438 \u043F\u0440.). \u0412 \u0434\u0440\u0443\u0433\u0438\u0445 \u0441\u043B\u0443\u0447\u0430\u044F\u0445, \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u044B \u043E\u0447\u0435\u043D\u044C \u0441\u043B\u043E\u0436\u043D\u044B\u0445 \u043E\u0442\u0440\u044B\u0432\u043A\u043E\u0432 \u0434\u043E\u043B\u0436\u043D\u044B \u0434\u0435\u043B\u0430\u0442\u044C\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u043E\u0442\u043A\u0440\u043E\u0432\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u0432\u044B \u043F\u0440\u043E\u0441\u0442\u043E \u0437\u0430\u0441\u0442\u0440\u044F\u043D\u0435\u0442\u0435 \u0438 \u043D\u0435 \u0441\u043C\u043E\u0436\u0435\u0442\u0435 \u0431\u043E\u043B\u044C\u0448\u0435 \u043F\u0440\u043E\u0434\u0432\u0438\u0433\u0430\u0442\u044C\u0441\u044F \u0432\u043F\u0435\u0440\u0435\u0434. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u043F\u043E\u0432\u0442\u043E\u0440\u044F\u044E\u0449\u0438\u0435\u0441\u044F \u043E\u0431\u0440\u0430\u0449\u0435\u043D\u0438\u044F \u043A \u0413\u043E\u0441\u043F\u043E\u0434\u0443 \u0440\u0430\u0434\u0443\u044E\u0442 \u0415\u0433\u043E, \u0438 \u041C\u0438\u043B\u043E\u0441\u0435\u0440\u0434\u043D\u044B\u0439 \u0434\u0430\u0435\u0442, \u043D\u0430\u043A\u043E\u043D\u0435\u0446, \u043F\u0435\u0440\u0435\u0432\u043E\u0434, \u0447\u0442\u043E \u043F\u043E \u0431\u043E\u043B\u044C\u0448\u0435\u0439 \u0447\u0430\u0441\u0442\u0438 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C \u0415\u0433\u043E ahaituk\u012B karu\u1E47\u0101, \u0438\u043B\u0438 \u0431\u0435\u0441\u043F\u0440\u0438\u0447\u0438\u043D\u043D\u044B\u043C \u0441\u043E\u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0435\u043C. \u042F \u0438\u043C\u0435\u043B \u0432 \u0432\u0438\u0434\u0443, \u0447\u0442\u043E \u0438\u0437 \u0447\u0438\u0441\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u044F \u041E\u043D \u0434\u0430\u0435\u0442 \u0441\u043E\u043A\u0440\u044B\u0442\u044B\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F, \u043E\u0441\u0432\u0435\u0449\u0430\u044F \u0438\u0445 \u0438\u0437 \u0433\u043B\u0443\u0431\u0438\u043D \u0421\u0432\u043E\u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0411\u044B\u0442\u0438\u044F, \u0438 \u0432 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0438 &quot;\u043A\u0430\u0436\u0443\u0449\u0435\u0433\u043E\u0441\u044F&quot;\u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0447\u0438\u043A\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043E\u0442\u043A\u0440\u043E\u0432\u0435\u043D\u0438\u0435. \u042D\u0442\u043E \u0441\u0432\u0435\u0442 \u015A\u0101nta, \u0432\u0441\u043F\u044B\u0448\u043A\u0430 \u041C\u0438\u0440\u0430, \u043E \u0447\u0435\u043C \u0441\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0443\u044E\u0442 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0435 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u044B \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u044B Vij\xF1\u0101nabhairava. \u0412 \u043A\u043E\u043D\u0446\u0435 \u043A\u043E\u043D\u0446\u043E\u0432, \u0432\u0441\u0435 \u044D\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u0415\u0433\u043E \u0440\u0430\u0431\u043E\u0442\u0430 \u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u043E. \u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u044D\u0442\u043E \u0415\u0433\u043E \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0435 \u041F\u0438\u0441\u0430\u043D\u0438\u044F. \u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435, \u043A\u043E\u0433\u0434\u0430 \u0432\u044B \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u0442\u0435 \u044D\u0442\u043E\u0442 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0439 \u044F\u0437\u044B\u043A, \u0432\u0430\u0448\u0430 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442, \u0438 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u041E\u043D \u043E\u0434\u0438\u043D. \u041D\u0435 \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0437\u0434\u0435\u0441\u044C \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439! \u0422\u043E\u0433\u043E, \u043A\u043E\u0433\u043E \u0432\u044B \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0435 &quot;\u0442\u044B&quot; \u043D\u0435 \u0435\u0441\u0442\u044C &quot;\u0442\u044B&quot;, \u0430 &quot;\u041E\u043D&quot; \u0432\u0441\u0435\u0433\u0434\u0430.</p></li></ol></div>',2),r=[i];function o(s,n,k,u,v,d){return m(),e("div",null,r)}var l=a(p,[["render",o]]);export{h as __pageData,l as default};
